/**
 * MMS Worker Daemon Runner
 *
 * Entry point for starting all background workers.
 * Handles graceful shutdown and health monitoring.
 *
 * Usage:
 *   bun run src/workers/runner.ts
 *   or
 *   WORKERS=optimizer,drift_monitor bun run src/workers/runner.ts
 *
 * Environment Variables:
 *   WORKERS - Comma-separated list of workers to start (default: all)
 *   REDIS_HOST - Redis server host (default: localhost)
 *   REDIS_PORT - Redis server port (default: 6379)
 *   REDIS_PASSWORD - Redis password (optional)
 *
 * @see specs/002-architecture.md Section 2.4 - Worker Layer
 * @see specs/004-domain-services.md Section 4.8
 */

import { logger } from '../lib/logging/logger';
import {
  registerWorker,
  closeAllWorkers,
  getWorkersHealth,
  QUEUE_NAMES,
  type WorkerJobContext,
} from './index';

// Import all worker processors
import { processOptimizerJob } from './processors/optimizer';
import { processDriftMonitorJob } from './processors/drift-monitor';
import { processIngestionJob } from './processors/ingestion';
import { processMaximoSyncJob } from './processors/maximo-sync';
import { processStrategicPlannerJob } from './processors/strategic-planner';
import { processNotificationJob } from './processors/notification';
import { processTacticalSchedulerJob } from './processors/tactical-scheduler';
import { processManhourLevelingJob } from './processors/manhour-leveling';
import { processReportJob } from './processors/report';


// =============================================================================
// Worker Registry
// =============================================================================

const log = logger.child({ module: 'worker-runner' });

/**
 * Available worker processors
 */
const WORKER_PROCESSORS: Record<
  keyof typeof QUEUE_NAMES,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  ((context: WorkerJobContext<any>) => Promise<unknown>) | null
> = {
  INGESTION: processIngestionJob,
  TACTICAL_SCHEDULER: processTacticalSchedulerJob,
  STRATEGIC_PLANNER: processStrategicPlannerJob,
  OPTIMIZER: processOptimizerJob,
  MANHOUR_LEVELING: processManhourLevelingJob,
  DRIFT_MONITOR: processDriftMonitorJob,
  NOTIFICATION: processNotificationJob,
  REPORT: processReportJob,
  MAXIMO_SYNC: processMaximoSyncJob,
};

// =============================================================================
// Worker Startup
// =============================================================================

/**
 * Start specified workers or all available workers
 *
 * @param workerKeys - Optional list of worker keys to start
 */
export async function startWorkers(
  workerKeys?: Array<keyof typeof QUEUE_NAMES>
): Promise<void> {
  const keys = workerKeys ?? (Object.keys(WORKER_PROCESSORS) as Array<keyof typeof QUEUE_NAMES>);

  log.info({ workers: keys }, 'Starting workers');

  for (const key of keys) {
    const processor = WORKER_PROCESSORS[key];

    if (!processor) {
      log.warn({ worker: key }, 'Worker processor not implemented, skipping');
      continue;
    }

    try {
      registerWorker(key, processor);
      log.info({ worker: key, queue: QUEUE_NAMES[key] }, 'Worker registered');
    } catch (error) {
      log.error({ worker: key, error }, 'Failed to register worker');
      throw error;
    }
  }

  const health = await getWorkersHealth();
  log.info(
    {
      totalWorkers: health.length,
      running: health.filter((w) => w.isRunning).length,
    },
    'All workers started'
  );
}

// =============================================================================
// Graceful Shutdown
// =============================================================================

let isShuttingDown = false;

async function handleShutdown(signal: string): Promise<void> {
  if (isShuttingDown) {
    log.warn({ signal }, 'Shutdown already in progress');
    return;
  }

  isShuttingDown = true;
  log.info({ signal }, 'Received shutdown signal, closing workers');

  try {
    await closeAllWorkers();
    log.info('All workers closed successfully');
    process.exit(0);
  } catch (error) {
    log.error({ error }, 'Error during worker shutdown');
    process.exit(1);
  }
}

// =============================================================================
// Main Entry Point
// =============================================================================

async function main(): Promise<void> {
  log.info('MMS Worker Daemon starting');

  // Register signal handlers for graceful shutdown
  process.on('SIGTERM', () => handleShutdown('SIGTERM'));
  process.on('SIGINT', () => handleShutdown('SIGINT'));

  // Parse WORKERS environment variable
  const workersEnv = process.env['WORKERS'];
  let workerKeys: Array<keyof typeof QUEUE_NAMES> | undefined;

  if (workersEnv) {
    const requestedWorkers = workersEnv.split(',').map((w) => w.trim().toUpperCase());
    workerKeys = requestedWorkers.filter((w) =>
      Object.keys(QUEUE_NAMES).includes(w)
    ) as Array<keyof typeof QUEUE_NAMES>;

    if (workerKeys.length === 0) {
      log.error({ requested: requestedWorkers }, 'No valid workers specified');
      process.exit(1);
    }

    log.info({ workers: workerKeys }, 'Starting specified workers');
  } else {
    log.info('Starting all available workers');
  }

  try {
    await startWorkers(workerKeys);
  } catch (error) {
    log.error({ error }, 'Failed to start workers');
    process.exit(1);
  }

  // Log health status periodically
  const healthInterval = setInterval(async () => {
    if (isShuttingDown) {
      clearInterval(healthInterval);
      return;
    }

    try {
      const health = await getWorkersHealth();
      const running = health.filter((w) => w.isRunning).length;
      const paused = health.filter((w) => w.isPaused).length;

      log.debug(
        { total: health.length, running, paused },
        'Worker health check'
      );

      // Alert if any workers are not running
      const notRunning = health.filter((w) => !w.isRunning && !w.isPaused);
      if (notRunning.length > 0) {
        log.warn(
          { workers: notRunning.map((w) => w.queueName) },
          'Some workers are not running'
        );
      }
    } catch (error) {
      log.error({ error }, 'Health check failed');
    }
  }, 60000); // Every minute

  log.info('Worker daemon running. Press Ctrl+C to stop.');
}

// Run if this is the main module
if (import.meta.main) {
  main().catch((error) => {
    console.error('Worker daemon failed:', error);
    process.exit(1);
  });
}

// Export for testing
export { handleShutdown, WORKER_PROCESSORS };

/**
 * MMS Database Connection
 *
 * PostgreSQL connection pool using postgres.js driver with Drizzle ORM.
 * Configured for production use with health checks and connection limits.
 *
 * Environment Variables:
 * - DATABASE_URL: PostgreSQL connection string (required)
 * - DATABASE_MAX_CONNECTIONS: Max pool size (default: 20)
 * - DATABASE_SSL: Enable SSL (default: true in production)
 *
 * @see specs/008-operations-deployment.md for production configuration
 */

import { drizzle } from 'drizzle-orm/postgres-js';
import postgres from 'postgres';
import * as schema from './schema';

/**
 * Database configuration from environment
 */
const config = {
  url: process.env['DATABASE_URL'] ?? 'postgresql://mms:mms_dev_password@localhost:5432/mms',
  maxConnections: parseInt(process.env['DATABASE_MAX_CONNECTIONS'] ?? '20', 10),
  ssl: process.env['DATABASE_SSL'] === 'true' || process.env['NODE_ENV'] === 'production',
  idleTimeout: 20, // seconds
  connectTimeout: 10, // seconds
};

/**
 * PostgreSQL connection pool
 *
 * Using postgres.js for:
 * - Native ESM support
 * - Excellent TypeScript support
 * - Prepared statements
 * - Connection pooling
 */
export const sql = postgres(config.url, {
  max: config.maxConnections,
  idle_timeout: config.idleTimeout,
  connect_timeout: config.connectTimeout,
  ssl: config.ssl ? { rejectUnauthorized: false } : false,
  // Prepare statements for better performance
  prepare: true,
  // Transform column names from snake_case to camelCase
  // Note: Drizzle handles this, so we keep original names
  transform: {
    undefined: null,
  },
  // Connection event handlers for logging/monitoring
  onnotice: () => {
    // Suppress notices in production
  },
});

/**
 * Drizzle ORM instance
 *
 * Provides type-safe query builder with full schema awareness.
 * All queries automatically use the connection pool.
 */
export const db = drizzle(sql, {
  schema,
  logger: process.env['NODE_ENV'] === 'development',
});

/**
 * Database health check
 *
 * Use this for liveness/readiness probes in Kubernetes.
 * Returns true if the database is reachable and responsive.
 */
export async function checkDatabaseHealth(): Promise<boolean> {
  try {
    const result = await sql`SELECT 1 as health`;
    return result.length === 1 && result[0]?.health === 1;
  } catch {
    return false;
  }
}

/**
 * Graceful shutdown
 *
 * Close all database connections gracefully.
 * Call this during application shutdown.
 */
export async function closeDatabaseConnection(): Promise<void> {
  await sql.end();
}

/**
 * Database transaction helper
 *
 * Executes a function within a database transaction.
 * Automatically commits on success or rolls back on error.
 *
 * @example
 * const result = await withTransaction(async (tx) => {
 *   await tx.insert(trains).values({ ... });
 *   await tx.insert(pmSchedule).values({ ... });
 *   return { success: true };
 * });
 */
export type Transaction = Parameters<Parameters<typeof db.transaction>[0]>[0];

export async function withTransaction<T>(
  fn: (tx: Transaction) => Promise<T>
): Promise<T> {
  return db.transaction(async (tx) => fn(tx));
}

// Export types for use in services
export type Database = typeof db;

